import React from "react";
import { useParams } from "react-router-dom";
import { Container, Typography, Box } from "@mui/material";
import { doctors } from "../data/doctors";

const { hospitalId } = useParams();
const hospitalDoctors = doctors.filter(
  (d) => d.hospitalId === Number(hospitalId),
);

const DoctorsList = () => {
  const { hospitalId } = useParams();

  return (
    <Container maxWidth="lg" sx={{ py: 6 }}>
      <Typography variant="h4" gutterBottom align="center">
        Doctors at Hospital #{hospitalId}
      </Typography>

      <Box sx={{ textAlign: "center", mt: 4 }}>
        <Typography variant="h6" color="text.secondary">
          This is the doctors list page for hospital ID {hospitalId}
        </Typography>
        <Typography sx={{ mt: 2 }}>
          (Add real doctor cards with photos and "View Profile" buttons here
          later)
        </Typography>
      </Box>
    </Container>
  );
};

export default DoctorsList;
